// Detectar novo vs recorrente + normalizar payload
const item = $input.item.json;
const body = item.body || {};
const sender = body.sender || 'unknown';
const name = body.name || '';
const first_interaction = body.first_interaction !== false; // default true
const consent = body.consentimento_lgpd === true;

// LGPD art. 7, I: consentimento explicito obrigatorio para primeiro contato
const needs_consent = first_interaction && !consent;

return { json: {
  sender,
  name: name || (first_interaction ? '' : 'cliente'),
  first_interaction,
  consent,
  needs_consent,
  message_id: body.message_id || `welcome-${sender}-${Date.now()}`,
  instance: body.instance || 'unknown'
}};
